B.Qm=new A.Z("\u6c34\u306b\u306a\u308c\u3001\u53cb\u3088\u3002","Be water, my friend.")
B.QN=new A.Z("\u8003\u3048\u308b\u306a\u3001\u611f\u3058\u308d\u3002","Don't think. Feel.")
B.QO=new A.Z("\u6557\u5317\u306f\u5fc3\u306e\u72b6\u614b\u3060\u3002\u8ca0\u3051\u3092\u8a8d\u3081\u306a\u3044\u9650\u308a\u3001\u8ab0\u3082\u672c\u5f53\u306b\u306f\u6557\u308c\u306a\u3044\u3002","Defeat is a state of mind. No one is ever defeated until defeat has been accepted as a reality.")
B.Qf=new A.Z("\u77e5\u308b\u3060\u3051\u3067\u306f\u8db3\u308a\u306a\u3044\u3001\u5b9f\u8df5\u305b\u3088\u3002\u610f\u5fd7\u3060\u3051\u3067\u306f\u8db3\u308a\u306a\u3044\u3001\u884c\u52d5\u305b\u3088\u3002","Knowing is not enough, we must apply. Willing is not enough, we must do.")
B.R_=new A.Z("\u9593\u9055\u3044\u3092\u6050\u308c\u308b\u306a\u3002\u305d\u308c\u306f\u9032\u6b69\u3057\u3066\u3044\u306a\u3044\u8a3c\u62e0\u3060\u3002","Mistakes are always forgivable, if one has the courage to admit them.")
B.QP=new A.Z("\u76ee\u6a19\u306f\u5e38\u306b\u4e0a\u306b\u3002\u81ea\u5206\u306e\u9650\u754c\u3092\u8d85\u3048\u308d\u3002","A goal is not always meant to be reached, it often serves simply as something to aim at.")
B.QE=new A.Z("\u30b7\u30f3\u30d7\u30eb\u3055\u3053\u305d\u7a76\u6975\u306e\u6d17\u7df4\u3067\u3042\u308b\u3002","Simplicity is the key to brilliance.")
B.PW=new A.Z("\u4f7f\u3048\u308b\u3082\u306e\u3092\u5438\u53ce\u3057\u3001\u4f7f\u3048\u306a\u3044\u3082\u306e\u3092\u6368\u3066\u3001\u81ea\u5206\u3060\u3051\u306e\u3082\u306e\u3092\u52a0\u3048\u3088\u3002","Absorb what is useful, discard what is useless and add what is specifically your own.")
B.Q3=new A.Z("\u9577\u3044\u65c5\u3082\u4e00\u6b69\u304b\u3089\u59cb\u307e\u308b\u3002","A journey of a thousand miles begins with a single step.")
B.Rb=new A.Z("\u578b\u3092\u5b66\u3073\u3001\u578b\u3092\u5b88\u308a\u3001\u578b\u3092\u7834\u308c\u3002","Learn the rules so you know how to break them properly.")
B.PQ=new A.Z("\u901f\u3055\u3068\u306f\u898b\u3048\u306a\u3044\u3053\u3068\u3067\u306f\u306a\u3044\u3002\u9069\u5207\u306a\u6642\u306b\u52d5\u304f\u3053\u3068\u3060\u3002","Speed is not about seeing \u2014 it is about moving at the right time.")
B.Q_=new A.Z("\u4e00\u4e07\u901a\u308a\u306e\u8e74\u308a\u3092\u4e00\u5ea6\u305a\u3064\u7df4\u7fd2\u3057\u305f\u8005\u306f\u6016\u304f\u306a\u3044\u3002\u4e00\u3064\u306e\u8e74\u308a\u3092\u4e00\u4e07\u56de\u7df4\u7fd2\u3057\u305f\u8005\u304c\u6016\u3044\u3002","I fear not the man who has practiced 10,000 kicks once, but I fear the man who has practiced one kick 10,000 times.")
B.Qn=new A.Z("\u81ea\u5206\u3092\u8868\u73fe\u3059\u308b\u52c7\u6c17\u3092\u6301\u3066\u3002","Always be yourself, express yourself, have faith in yourself.")
B.Qz=new A.Z("\u4eba\u751f\u306e\u5927\u304d\u306a\u904e\u3061\u306f\u3001\u9593\u9055\u3048\u308b\u3053\u3068\u3092\u5e38\u306b\u6050\u308c\u308b\u3053\u3068\u3060\u3002","Life's battles don't always go to the stronger or faster man. But sooner or later, the man who wins is the man who thinks he can.")
B.QX=new A.Z("\u81ea\u5206\u3092\u77e5\u308b\u3053\u3068\u304c\u5168\u3066\u306e\u77e5\u6075\u306e\u59cb\u307e\u308a\u3060\u3002","To know oneself is to study oneself in action with another person.")
B.Q7=new A.Z("\u5f62\u306b\u3053\u3060\u308f\u308b\u306a\u3002\u5f62\u306a\u304d\u5f62\u3001\u305d\u308c\u304c\u7a76\u6975\u3060\u3002","Be formless, shapeless, like water.")
B.Q0=new A.Z("\u9650\u754c\u306f\u5b58\u5728\u3057\u306a\u3044\u3002\u3042\u308b\u306e\u306f\u505c\u6ede\u3060\u3051\u3060\u3002\u305d\u3053\u306b\u7559\u307e\u308b\u306a\u3002","There are no limits. There are only plateaus, and you must not stay there.")
B.QF=new A.Z("\u5fcd\u8010\u306f\u96c6\u4e2d\u529b\u3067\u3042\u308a\u3001\u5f37\u3055\u3067\u3042\u308b\u3002","Patience is not passive; on the contrary, it is concentrated strength.")
B.Q8=new A.Z("\u5e78\u798f\u3068\u306f\u4f55\u304b\u3092\u6210\u3057\u9042\u3052\u305f\u8005\u3060\u3051\u304c\u611f\u3058\u308b\u3082\u306e\u3060\u3002","Ever since I was a child I have had this instinctive urge for expansion and growth.")
B.Qw=new A.Z("\u771f\u306e\u5f37\u3055\u306f\u3001\u81ea\u5206\u81ea\u8eab\u3092\u5236\u5fa1\u3067\u304d\u308b\u8005\u306b\u3042\u308b\u3002","The key to immortality is first living a life worth remembering.")
B.Qa=new A.Z("\u6d41\u308c\u306b\u8eab\u3092\u4efb\u305b\u3001\u67d4\u8edf\u306b\u5bfe\u5fdc\u305b\u3088\u3002","You must be shapeless, formless, like water.")
B.Q9=new A.Z("\u6210\u529f\u3068\u306f\u65e5\u3005\u306e\u7df4\u7fd2\u306e\u7a4d\u307f\u91cd\u306d\u3060\u3002\u4e00\u65e5\u306b\u3057\u3066\u6210\u308b\u3082\u306e\u3067\u306f\u306a\u3044\u3002","Long-term consistency trumps short-term intensity.")
B.QV=new A.Z("\u5049\u5927\u306a\u5e2b\u306f\u6307\u3055\u3059\u304c\u3001\u6307\u3092\u898b\u308b\u306a\u3002\u6708\u3092\u898b\u308d\u3002","It's like a finger pointing away to the moon. Don't concentrate on the finger or you will miss all that heavenly glory.")
B.QM=new A.Z("\u8ca0\u3051\u305f\u5f8c\u306b\u3069\u3046\u7acb\u3061\u4e0a\u304c\u308b\u304b\u304c\u3001\u304a\u524d\u3068\u3044\u3046\u4eba\u9593\u3092\u6c7a\u3081\u308b\u3002","The successful warrior is the average man, with laser-like focus.")
B.Qj=new A.Z("\u5668\u3092\u7a7a\u306b\u3057\u308d\u3002\u305d\u3046\u3059\u308c\u3070\u65b0\u3057\u3044\u3082\u306e\u3067\u6e80\u305f\u3055\u308c\u308b\u3002","Empty your cup so that it may be filled.")
B.PX=new A.Z("\u8abf\u548c\u3068\u306f\u3001\u5bfe\u7acb\u306e\u4e2d\u306b\u3053\u305d\u898b\u51fa\u3055\u308c\u308b\u3002","In the middle of chaos lies opportunity.")
B.Ql=new A.Z("\u884c\u52d5\u3053\u305d\u304c\u771f\u5b9f\u3060\u3002\u8a00\u8449\u3067\u306f\u306a\u304f\u3002","If you spend too much time thinking about a thing, you will never get it done.")
B.Qs=new A.Z("\u5f37\u304f\u306a\u308b\u305f\u3081\u306b\u6226\u3046\u306e\u3067\u306f\u306a\u3044\u3002\u6226\u3046\u3053\u3068\u3067\u5f37\u304f\u306a\u308b\u306e\u3060\u3002","Do not pray for an easy life, pray for the strength to endure a difficult one.")
B.PZ=new A.Z("\u5909\u5316\u3053\u305d\u304c\u4e0d\u5909\u306e\u771f\u7406\u3060\u3002","The only way to deal with change is to embrace it.")
B.R5=new A.Z("\u4eca\u65e5\u3068\u3044\u3046\u65e5\u3092\u5168\u529b\u3067\u751f\u304d\u308d\u3002\u305d\u308c\u304c\u6700\u9ad8\u306e\u5fa9\u8b90\u3060\u3002","Real living is living for others.")
B.QW=new A.Z("\u601d\u3046\u3088\u3046\u306b\u306a\u308c\u3002","As you think, so shall you become.")
B.R7=new A.Z("\u7af9\u306f\u5d50\u306b\u66f2\u304c\u308b\u304c\u3001\u6298\u308c\u306a\u3044\u3002\u67d4\u8edf\u6027\u3053\u305d\u304c\u5f37\u3055\u3060\u3002","Notice that the stiffest tree is most easily cracked, while the bamboo survives by bending in the wind.")
B.Q2=new A.Z("\u5df1\u306e\u9650\u754c\u3092\u8a2d\u3051\u308b\u306a\u3002\u9650\u754c\u306f\u3042\u306a\u305f\u306e\u4e2d\u306b\u3042\u308b\u58c1\u3060\u3002","If you always put a limit on what you do, it will spread into your work and your life.")
B.PY=new A.Z("\u5e2b\u5320\u306f\u6249\u3092\u958b\u304f\u3002\u901a\u308b\u306e\u306f\u3042\u306a\u305f\u81ea\u8eab\u3060\u3002","A teacher is never a giver of truth \u2014 he is a guide, a pointer to the truth that each student must find.")
B.QU=new A.Z("\u771f\u306e\u719f\u9054\u3068\u306f\u81ea\u5206\u81ea\u8eab\u3092\u8d85\u3048\u308b\u3053\u3068\u304b\u3089\u751f\u307e\u308c\u308b\u3002","True mastery transcends any particular art. It stems from mastery of oneself.")
B.QT=new A.Z("\u624d\u80fd\u306f\u7df4\u7fd2\u306b\u52dd\u3066\u306a\u3044\u3002","There are no shortcuts in the cultivation of kung fu. You must practice hard, diligently, and consistently.")
B.Q4=new A.Z("\u6050\u308c\u3092\u77e5\u308b\u3053\u3068\u3067\u3001\u6050\u308c\u304b\u3089\u81ea\u7531\u306b\u306a\u308c\u308b\u3002","Fear comes from uncertainty; we can eliminate the fear within us when we know ourselves better.")
B.Qx=new A.Z("\u6642\u9593\u3092\u611b\u3059\u308b\u306a\u3089\u3001\u6642\u9593\u3092\u7121\u99c4\u306b\u3059\u308b\u306a\u3002\u6642\u9593\u3053\u305d\u304c\u547d\u3060\u3002","If you love life, don't waste time, for time is what life is made up of.")
B.Q6=new A.Z("\u4eba\u751f\u306e\u610f\u5473\u3068\u306f\u3001\u305d\u308c\u3092\u751f\u304d\u5207\u308b\u3053\u3068\u306b\u3042\u308b\u3002","The meaning of life is that it is to be lived.")
B.Qe=new A.Z("\u65e5\u3005\u5897\u3084\u3059\u306e\u3067\u306f\u306a\u304f\u3001\u65e5\u3005\u524a\u308c\u3002\u4e0d\u8981\u306a\u3082\u306e\u3092\u5207\u308a\u843d\u3068\u305b\u3002","It is not daily increase but daily decrease \u2014 hack away at the unessential.")
B.R3=new A.Z("\u5b66\u3076\u3068\u306f\u767a\u898b\u3059\u308b\u3053\u3068\u3060\u3002\u767a\u898b\u3059\u308b\u3053\u3068\u3068\u306f\u3001\u81ea\u7531\u306b\u306a\u308b\u3053\u3068\u3060\u3002","Learning is never cumulative, it is a movement of knowing which has no beginning and no end.")
B.QH=new A.Z("\u52d5\u4f5c\u306e\u7121\u99c4\u3092\u7701\u3051\u3002\u4e00\u3064\u306e\u52d5\u4f5c\u3067\u52dd\u8ca0\u3092\u6c7a\u3081\u308d\u3002","Economy of motion \u2014 use no more than is necessary.")
B.Q1=new A.Z("\u82b8\u8853\u3068\u306f\u81ea\u5df1\u8868\u73fe\u3060\u3002\u5f62\u5f0f\u3067\u306f\u306a\u3044\u3002","Art calls for complete mastery of techniques, developed by reflection within the soul.")
B.R0=new A.Z("\u6012\u308a\u306f\u9727\u3060\u3002\u305d\u308c\u306f\u5224\u65ad\u3092\u66c7\u3089\u305b\u308b\u3002","Anger is a wind which blows out the lamp of the mind.")
B.R4=new A.Z("\u5b8c\u5168\u306a\u935b\u932c\u3068\u306f\u5fc3\u3068\u4f53\u306e\u7d71\u4e00\u3060\u3002","The perfect technique is the expression of the mind and the body as one.")
B.Qr=new A.Z("\u9759\u306e\u4e2d\u306b\u52d5\u3042\u308a\u3001\u52d5\u306e\u4e2d\u306b\u9759\u3042\u308a\u3002","In stillness there is movement, in movement there is stillness.")
B.R6=new A.Z("\u610f\u8b58\u306e\u904e\u5270\u3053\u305d\u304c\u3001\u3042\u3089\u3086\u308b\u52d5\u4f5c\u306e\u59a8\u3052\u3068\u306a\u308b\u3002","The consciousness of self is the greatest hindrance to the proper execution of all physical action.")
B.Qp=new A.Z("\u6b66\u8853\u306f\u5df1\u306e\u6b20\u70b9\u3092\u6620\u3059\u93e1\u3060\u3002","The martial arts are a mirror to reflect your own blemishes.")
B.QB=new A.Z("\u6628\u65e5\u3088\u308a\u4eca\u65e5\u3001\u4eca\u65e5\u3088\u308a\u660e\u65e5\u3002\u5e38\u306b\u524d\u9032\u305b\u3088\u3002","Seek the highest form of the art you are studying \u2014 perfect yourself, transcend technique.")
B.Qq=new A.Z("\u5b64\u72ec\u3092\u6050\u308c\u308b\u306a\u3002\u5b64\u72ec\u306e\u4e2d\u3067\u3053\u305d\u81ea\u5206\u3068\u5411\u304d\u5408\u3048\u308b\u3002","In the silence of solitude, you hear the clearest truth.")
B.Qh=new A.Z("\u771f\u306e\u6b66\u9053\u5bb6\u306f\u5e73\u548c\u3092\u611b\u3059\u308b\u3002","The true martial artist does not fight for aggression \u2014 he cultivates the art of peace.")
B.Qo=new A.Z("\u4f53\u304c\u75b2\u308c\u305f\u3068\u304d\u3001\u7cbe\u795e\u304c\u524d\u306b\u9032\u307e\u305b\u308b\u3002","When your body says stop, your spirit says continue.")
B.Qb=new A.Z("\u6249\u3092\u53e9\u304d\u7d9a\u3051\u308d\u3002\u30c1\u30e3\u30f3\u30b9\u306f\u7528\u610f\u3055\u308c\u305f\u8005\u306e\u3068\u3053\u308d\u306b\u3084\u3063\u3066\u6765\u308b\u3002","Opportunity does not knock \u2014 it presents itself when you beat down the door.")
B.Qk=new A.Z("\u6b66\u8853\u306f\u6575\u3092\u5012\u3059\u6280\u3067\u306f\u306a\u304f\u3001\u81ea\u5206\u3092\u8d85\u3048\u308b\u6280\u3060\u3002","Martial art is not about defeating an opponent \u2014 it is about exceeding your own limitations.")
B.Q5=new A.Z("\u5931\u6557\u306f\u7d42\u308f\u308a\u3067\u306f\u306a\u3044\u3002\u305d\u308c\u306f\u65b0\u3057\u3044\u59cb\u307e\u308a\u3060\u3002","Defeat is not a disgrace \u2014 it is only a new beginning.")
B.Qy=new A.Z("\u9053\u3092\u77e5\u308b\u3053\u3068\u3068\u9053\u3092\u6b69\u304f\u3053\u3068\u306f\u9055\u3046\u3002","Knowing the way and walking the way are two entirely different things.")
B.Qu=new A.Z("\u5263\u3088\u308a\u901f\u304f\u3001\u6c34\u3088\u308a\u67d4\u3089\u304b\u304f\u3001\u708e\u3088\u308a\u6fc0\u3057\u304f\u5728\u308c\u3002","Be faster than the sword, softer than water, fiercer than fire.")
B.Qc=new A.Z("\u9375\u306f\u4eca\u3053\u306e\u77ac\u9593\u3060\u3002\u904e\u53bb\u3067\u3082\u672a\u6765\u3067\u3082\u306a\u3044\u3002","The key is now \u2014 not yesterday, not tomorrow, but this very moment.")
B.Rd=new A.Z("\u5168\u529b\u3092\u51fa\u3057\u5207\u3063\u305f\u5f8c\u306b\u6b8b\u308b\u306e\u304c\u3001\u672c\u5f53\u306e\u81ea\u5206\u3060\u3002","What you are left with after you have given everything is who you truly are.")
B.Rc=new A.Z("\u3069\u308c\u3060\u3051\u77e5\u3063\u3066\u3044\u308b\u304b\u3067\u306f\u306a\u304f\u3001\u3069\u308c\u3060\u3051\u4f7f\u3048\u308b\u304b\u3060\u3002","It is not how much you know, but how much you can use.")
